#include <iostream>
#include <string>

int main() {
  int number = 42;
  double pi = 3.14;
  std::string message = "Hello, C++!";
  bool isActive = true;
  std::cout << "Number: " << number << std::endl;
  std::cout << "Pi: " << pi << std::endl;
  std::cout << "Message: " << message << std::endl;
  std::cout << "Is Active: " << isActive << std::endl;
  return 0;
}
// Output:
// Number: 42
// Pi: 3.14
// Message: Hello, C++!
// Is Active: 1

#include <iostream>

int main() {
  int number = 10;
  if (number > 0) {
    std::cout << "Number is positive" << std::endl;
  } else if (number < 0) {
    std::cout << "Number is negative" << std::endl;
  } else {
    std::cout << "Number is zero" << std::endl;
  }
  return 0;
}
// Output:
// Number is positive

#include <iostream>

int main() {
  for (int i = 1; i <= 5; i++) {
    std::cout << "Iteration: " << i << std::endl;
  }
  return 0;
}
// Output:
// Iteration: 1
// Iteration: 2
// Iteration: 3
// Iteration: 4
// Iteration: 5

#include <iostream>

int add(int a, int b) {
  int result = a + b;
  return result;
}

int main() {
  int sum = add(5, 3);
  std::cout << "Sum: " << sum << std::endl;
  return 0;
}
// Output:
// Sum: 8

#include <iostream>
#include <string>

class Person {
public:
  std::string name = "Alice";
  int age = 25;

  void display() {
    std::cout << "Name: " << name << ", Age: " << age << std::endl;
  }
};

int main() {
  Person person;
  person.display();
  return 0;
}
// Output:
// Name: Alice, Age: 25

